  state STRING OPTIONS(description="State or province of primary residence"),
  country STRING OPTIONS(description="ISO 3166-1 alpha-2 country code"),
  postal_code STRING OPTIONS(policy_tags=["projects/telco/locations/global/taxonomies/pii/policyTags/address"]) OPTIONS(description="Postal / ZIP code of primary residence"),
  geo_latitude FLOAT64 OPTIONS(policy_tags=["projects/telco/locations/global/taxonomies/pii/policyTags/location"]) OPTIONS(description="Latitude of primary residence (WGS 84)"),
  geo_longitude FLOAT64 OPTIONS(policy_tags=["projects/telco/locations/global/taxonomies/pii/policyTags/location"]) OPTIONS(description="Longitude of primary residence (WGS 84)"),
  subscriber_type STRING NOT NULL OPTIONS(description="Billing relationship type (postpaid/prepaid/hybrid)"),
  subscriber_segment STRING OPTIONS(description="High-level commercial segment (mass/gold/platinum/vip)"),
  lifecycle_stage STRING NOT NULL OPTIONS(description="Customer lifecycle stage (prospect/active/dormant/churned)"),
