  credit_score FLOAT64 OPTIONS(description="Internal or bureau credit score (0-1000 scale)"),
  preferred_channel STRING OPTIONS(description="Preferred contact channel (sms/email/push/call/whatsapp)"),
  language_preference STRING OPTIONS(description="Preferred language (ISO 639-1 code)"),
  kyc_status STRING OPTIONS(description="Know-Your-Customer verification status (pending/verified/rejected/expired)"),
  kyc_date DATE OPTIONS(description="Date KYC verification was last completed or refreshed"),
  sim_type STRING OPTIONS(description="SIM form factor (physical/eSIM/iSIM)"),
  network_type STRING OPTIONS(description="Highest registered network technology (2G/3G/4G/5G)"),
  handset_model STRING OPTIONS(description="Current primary handset model name"),
  os_type STRING OPTIONS(description="Operating system of primary device (android/ios/other)"),
  activation_date DATE NOT NULL OPTIONS(description="Date the subscriber line was first activated"),
  last_activity_date DATE OPTIONS(description="Date of most recent network or billing activity"),
  churn_risk_score FLOAT64 OPTIONS(description="Predictive churn probability (0.0 - 1.0)"),
  lifetime_value NUMERIC OPTIONS(description="Estimated customer lifetime value in local currency"),
  referral_code STRING OPTIONS(description="Referral or promo code used at acquisition"),
  dealer_code STRING OPTIONS(description="Acquiring dealer / point-of-sale code"),
  credit_class STRING OPTIONS(description="Credit classification tier (A/B/C/D/E)"),
  status STRING NOT NULL OPTIONS(description="Subscriber line status (active/suspended/barred/terminated)"),
