  updated_at TIMESTAMP OPTIONS(description="Record last-update timestamp (UTC)")
)
PARTITION BY DATE_TRUNC(activation_date, DAY)
CLUSTER BY subscriber_id
OPTIONS(
  description="subscriber_profile table for subscriber domain"
);

